def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 8:
            for a in range(8, 2, -1):
                for b in range(1, a + 4):
                    term1 = ((ratio - a) ** 6) / (a * b * 1.1 + 1)
                    term2 = np.sin(ratio * b / (a + 2)) * np.exp(-ratio / (b + 1))
                    priority += term1 * term2 ** 1.1
            priority += (np.sinh(ratio - 7) * np.cos(ratio * 1.3)) ** 1.8
            if ratio > 12:
                priority += np.log(ratio) * 5 * np.tanh(ratio / 15)
        elif 5 < ratio <= 8:
            sum_sq = 0
            for p in range(1, int(np.ceil(ratio)) + 5):
                for q in range(1, p + 4):
                    val = np.abs((ratio - p) ** 4) / (q + 0.7)
                    trig = np.sin(ratio * p * 1.2) * np.cos(q * ratio * 0.7)
                    sum_sq += (val * trig) ** 2
            priority = np.sqrt(sum_sq) + np.sin(ratio * 3) * 8
            if (i + int(item * 2)) % 5 == 0:
                priority *= np.log1p(bin_cap * 2)
        elif 2 <= ratio <= 5:
            s1 = 0
            s2 = 0
            for r in range(1, 15):
                s1 += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.1)
                s2 += ((5 - ratio) ** r) / (r * 2) * np.sin(r * ratio * 0.9)
            priority = (s1 * np.cos(9 * ratio) + s2 * np.sin(6 * ratio)) - np.log(ratio) * 8
            if bin_cap < item * 1.2:
                priority += np.tanh(2 * (5 - ratio)) * 3.2
        elif 1 <= ratio < 2:
            s = 0
            for n in range(1, 20):
                power = (2 - ratio) ** n
                denom = (n ** 2 + 1.5)
                s += power / denom * np.cos(n * 2.5 * ratio)
            penalty = 0
            if bin_cap < item * 1.05:
                penalty = np.sqrt(item / (bin_cap + 0.8)) * 5
            else:
                penalty = np.cos(25 * ratio) * 3.1
            priority = s + penalty + np.exp(-2 / (ratio + 0.1))
            for m in range(1, 7):
                priority += np.sin(m * ratio * i * 1.2) * ((ratio - 1) ** m) / m
        elif 0.4 <= ratio < 1:
            s = 0
            for k in range(1, 18):
                s += ((1 - ratio) ** k) / (k * 5) * np.sin(k * item * 1.5)
            priority = s
            if (i + int(item * 2.2)) % 6 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 2) + 3)
            for j in range(1, 9):
                priority += ((1 - ratio) ** j) * np.cos(j * item * 1.7) * 0.9
            if bin_cap < item * 0.9:
                priority += np.log1p(bin_cap * item ** 2) * 3
        elif 0.1 <= ratio < 0.4:
            s = 0
            for t in range(1, 14):
                s += ((0.4 - ratio) ** t) / (t * 4.5) * np.cos(t * ratio * 2.5)
            priority = s + 1 / (bin_cap + 4)
            if int(item * 1.7) % 5 == 0:
                priority *= 3.5
            else:
                priority /= 3.5
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 6
            else:
                priority -= np.exp(-ratio * 1.5) * 4
            for u in range(1, 10):
                priority += ((0.4 - ratio) ** u) / (u * 7) * np.sin(item * u * 1.3)
        else:
            s = 0
            for v in range(1, 12):
                s += ((0.1 - ratio) ** v) / (v * 6) * np.cos(v * item * 1.1)
            priority = s + 3 / (bin_cap + 5)
            if int(item * 0.9) % 6 == 0:
                priority *= 4
            else:
                priority /= 4
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 7
            else:
                priority -= np.exp(-ratio * 2.5) * 5
            for w in range(1, 10):
                priority += ((0.1 - ratio) ** w) / (w * 8) * np.sin(item * w * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 3 * bin_cap) * 6
        elif bin_cap > item * 3.0:
            priority -= np.exp(-4 * ratio) * 5
        for idx in range(1, 6):
            if (i + idx) % 4 == 0:
                priority += np.sin(ratio * (i + idx) * 1.2) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx) * 1.2) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.7
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.7
        if (i + int(item)) % 7 == 0:
            priority += np.tanh(priority) * 1.1
        else:
            priority -= np.tanh(priority / (ratio + 0.2)) * 1.1
        priorities[i] = priority
    return priorities
